INSERT INTO passages (id, title, topic, word_range, content, content_ja) VALUES (76, 'Universal Pre-K and the Science of Early Childhood Development', '教育', '1~1000',
INSERT INTO passage_questions (id, passage_id, question_number, question_type, question_text, explanation, correct_choice) VALUES
(226, 76, 1, 'comprehension',
INSERT INTO question_choices (question_id, choice_number, choice_text) VALUES
(226, 1, 'The fade-out effect is an inevitable consequence of all pre-K programs and cannot be mitigated regardless of program quality, funding levels, or instructional methods.'),
(226, 2, 'The fade-out effect has been conclusively attributed to flawed research methodologies in the original studies, and more rigorous recent analyses have shown that gains persist indefinitely.'),
(226, 3, 'Proponents argue that the fade-out effect reflects the poor quality of many publicly funded programs rather than an inherent limitation of early childhood education itself.'),
(226, 4, 'The fade-out effect is caused exclusively by the failure of K-12 schools to build upon early gains, and pre-K programs themselves bear no responsibility for the phenomenon.'),
(227, 1, 'They have portrayed public pre-K as an infringement on parental autonomy and a means of instilling progressive social values in young children.'),
(227, 2, 'They have argued that pre-K programs are economically inefficient because the per-pupil costs far exceed the long-term returns demonstrated by longitudinal research.'),
(227, 3, 'They have maintained that government-funded pre-K programs unfairly compete with private childcare providers, driving small businesses out of the early education market.'),
(227, 4, 'They have claimed that early formal education is developmentally harmful to children under five, citing neuroscience research that supports delayed school entry.'),
(228, 1, 'score above the national average on standardized mathematics and reading assessments administered at the end of third grade'),
(228, 2, 'graduate from high school and enroll in four-year colleges'),
(228, 3, 'demonstrate superior social skills and emotional resilience in middle school peer interactions'),
(228, 4, 'express positive attitudes toward public education and advocate for increased government funding of schools');
